from llama_index.retrievers.bm25 import BM25Retriever
from llama_index.core.retrievers import VectorIndexRetriever
from llama_index.core.query_engine import RetrieverQueryEngine
from llama_index.core.retrievers import BaseRetriever
from llama_index.core import QueryBundle
from llama_index.core.schema import NodeWithScore

class HybridRetriever(BaseRetriever):
    def __init__(self, vector_retriever, bm25_retriever):
        self._vector = vector_retriever
        self._bm25 = bm25_retriever

    def _retrieve(self, query_bundle: QueryBundle) -> list[NodeWithScore]:
        vector_nodes = self._vector.retrieve(query_bundle)
        bm25_nodes = self._bm25.retrieve(query_bundle)

        # Deduplicate by node ID, keep highest score
        seen = {}
        for n in vector_nodes + bm25_nodes:
            if n.node.node_id not in seen or n.score > seen[n.node.node_id].score:
                seen[n.node.node_id] = n
        return list(seen.values())

vector_retriever = VectorIndexRetriever(index=index, similarity_top_k=8)
bm25_retriever = BM25Retriever.from_defaults(index=index, similarity_top_k=8)

hybrid = HybridRetriever(vector_retriever, bm25_retriever)
query_engine = RetrieverQueryEngine.from_args(retriever=hybrid)

from llama_index.core.response_synthesizers import BaseSynthesizer
from llama_index.core.types import RESPONSE_TEXT_TYPE
from llama_index.core.schema import NodeWithScore, QueryBundle

class BulletPointSynthesizer(BaseSynthesizer):
    async def aget_response(
        self,
        query_str: str,
        text_chunks: list[str],
        **kwargs,
    ) -> RESPONSE_TEXT_TYPE:
        combined = "

".join(text_chunks[:5])  # use top-5 chunks
        prompt = (
            f"Based on the following context, answer the question in exactly 3 bullet points.

"
            f"Context:
{combined}

Question: {query_str}"
        )
        return await self._llm.acomplete(prompt)

    def get_response(self, query_str, text_chunks, **kwargs):
        import asyncio
        return asyncio.get_event_loop().run_until_complete(
            self.aget_response(query_str, text_chunks, **kwargs)
        )

synthesiser = BulletPointSynthesizer.from_defaults()
query_engine = RetrieverQueryEngine(
    retriever=VectorIndexRetriever(index=index, similarity_top_k=5),
    response_synthesizer=synthesiser,
)
